def word_break(s: str, wordDict) -> bool:
    words = set(wordDict)
    maxL = max((len(w) for w in words), default=0)
    n = len(s)
    dp = [False] * (n + 1)
    dp[0] = True
    for i in range(1, n + 1):
        for L in range(1, min(maxL, i) + 1):
            if dp[i - L] and s[i - L:i] in words:
                dp[i] = True
                break
    return dp[n]

